#!/usr/bin/env node
/**
 * UA Graph Validation Script
 * Validates knowledge graph for correctness, completeness, and quality
 */

const fs = require('fs');
const path = require('path');

// Valid types
const VALID_NODE_TYPES = [
  'file', 'function', 'class', 'module', 'concept', 'config', 'document',
  'service', 'table', 'endpoint', 'pipeline', 'schema', 'resource',
  'domain', 'flow', 'step'
];

const VALID_NODE_PREFIXES = [
  'file:', 'function:', 'class:', 'module:', 'concept:', 'config:', 'document:',
  'service:', 'table:', 'endpoint:', 'pipeline:', 'schema:', 'resource:',
  'domain:', 'flow:', 'step:'
];

const VALID_EDGE_TYPES = [
  'imports', 'exports', 'contains', 'inherits', 'implements', 'calls',
  'subscribes', 'publishes', 'middleware', 'reads_from', 'writes_to',
  'transforms', 'validates', 'depends_on', 'tested_by', 'configures',
  'related', 'similar_to', 'deploys', 'serves', 'migrates', 'documents',
  'provisions', 'routes', 'defines_schema', 'triggers', 'contains_flow',
  'flow_step', 'cross_domain'
];

const VALID_COMPLEXITY = ['simple', 'moderate', 'complex'];
const VALID_DIRECTIONS = ['forward', 'backward', 'bidirectional'];

function main() {
  const inputPath = process.argv[2];
  const outputPath = process.argv[3];

  if (!inputPath || !outputPath) {
    console.error('Usage: node ua-graph-validate.js <input-graph.json> <output-results.json>') > stderr;
    process.exit(1);
  }

  let graph;
  try {
    const content = fs.readFileSync(inputPath, 'utf8');
    graph = JSON.parse(content);
  } catch (err) {
    console.error(`Error reading or parsing graph file: ${err.message}`, stderr);
    process.exit(1);
  }

  const issues = [];
  const warnings = [];
  const stats = {
    totalNodes: 0,
    totalEdges: 0,
    totalLayers: 0,
    tourSteps: 0,
    nodeTypes: {},
    edgeTypes: {}
  };

  // Build node ID set for referential checks
  const nodeIds = new Set();
  const nodeById = {};

  // Detect domain graph
  const isDomainGraph = graph.nodes && graph.nodes.some(n =>
    n.type === 'domain' || n.type === 'flow' || n.type === 'step'
  );

  // Check 1: Schema validation
  if (!graph.nodes || !Array.isArray(graph.nodes)) {
    issues.push('Missing or invalid nodes array');
  } else {
    stats.totalNodes = graph.nodes.length;

    // Check for duplicate IDs
    const idCount = {};
    graph.nodes.forEach((node, idx) => {
      if (!node.id) {
        issues.push(`Node at index ${idx} missing required field 'id'`);
      } else {
        if (idCount[node.id]) {
          issues.push(`Duplicate node ID '${node.id}' at indices ${idCount[node.id]} and ${idx}`);
        }
        idCount[node.id] = idx;
        nodeIds.add(node.id);
        nodeById[node.id] = { node, idx };
      }

      // Count node types
      if (node.type) {
        stats.nodeTypes[node.type] = (stats.nodeTypes[node.type] || 0) + 1;
      }

      // Validate required fields
      if (!node.type || !VALID_NODE_TYPES.includes(node.type)) {
        issues.push(`Node '${node.id || idx}' has invalid type '${node.type}' - must be one of: ${VALID_NODE_TYPES.join(', ')}`);
      }
      if (!node.name || typeof node.name !== 'string' || node.name.trim() === '') {
        issues.push(`Node '${node.id}' has invalid name - must be non-empty string`);
      }
      if (!node.summary || typeof node.summary !== 'string' || node.summary.trim() === '') {
        issues.push(`Node '${node.id}' has invalid summary - must be non-empty string`);
      }
      if (!node.tags || !Array.isArray(node.tags) || node.tags.length === 0) {
        issues.push(`Node '${node.id}' has invalid tags - must be array with at least 1 element`);
      } else {
        const allLowercase = node.tags.every(t => typeof t === 'string' && t === t.toLowerCase() && t.includes('-'));
        if (!allLowercase) {
          warnings.push(`Node '${node.id}' tags should be lowercase hyphenated`);
        }
      }
      if (!node.complexity || !VALID_COMPLEXITY.includes(node.complexity)) {
        issues.push(`Node '${node.id}' has invalid complexity '${node.complexity}' - must be one of: ${VALID_COMPLEXITY.join(', ')}`);
      }

      // Check ID prefix matches type
      if (node.id && node.type) {
        const expectedPrefix = node.type + ':';
        if (!node.id.startsWith(expectedPrefix)) {
          warnings.push(`Node '${node.id}' type '${node.type}' does not match ID prefix '${expectedPrefix}'`);
        }
      }
    });
  }

  // Check 2: Referential integrity for edges
  if (!graph.edges || !Array.isArray(graph.edges)) {
    issues.push('Missing or invalid edges array');
  } else {
    stats.totalEdges = graph.edges.length;

    graph.edges.forEach((edge, idx) => {
      // Count edge types
      if (edge.type) {
        stats.edgeTypes[edge.type] = (stats.edgeTypes[edge.type] || 0) + 1;
      }

      if (!edge.source) {
        issues.push(`Edge at index ${idx} missing required field 'source'`);
      } else if (!nodeIds.has(edge.source)) {
        issues.push(`Edge at index ${idx} references non-existent source node '${edge.source}'`);
      }

      if (!edge.target) {
        issues.push(`Edge at index ${idx} missing required field 'target'`);
      } else if (!nodeIds.has(edge.target)) {
        issues.push(`Edge at index ${idx} references non-existent target node '${edge.target}'`);
      }

      if (!edge.type || !VALID_EDGE_TYPES.includes(edge.type)) {
        issues.push(`Edge at index ${idx} has invalid type '${edge.type}' - must be one of: ${VALID_EDGE_TYPES.join(', ')}`);
      }

      if (!edge.direction || !VALID_DIRECTIONS.includes(edge.direction)) {
        issues.push(`Edge at index ${idx} has invalid direction '${edge.direction}' - must be one of: ${VALID_DIRECTIONS.join(', ')}`);
      }

      if (typeof edge.weight !== 'number' || edge.weight < 0.0 || edge.weight > 1.0) {
        issues.push(`Edge at index ${idx} has invalid weight '${edge.weight}' - must be between 0.0 and 1.0`);
      }

      // Self-referencing edge check
      if (edge.source && edge.target && edge.source === edge.target) {
        warnings.push(`Edge at index ${idx} is self-referencing (source equals target)`);
      }
    });
  }

  // Check 3: Completeness
  if (stats.totalNodes === 0) {
    issues.push('Graph has no nodes - at least 1 node required');
  }
  if (stats.totalEdges === 0) {
    issues.push('Graph has no edges - at least 1 edge required');
  }

  // Check layers
  if (!graph.layers || !Array.isArray(graph.layers)) {
    if (!isDomainGraph) {
      issues.push('Missing or invalid layers array');
    }
  } else {
    stats.totalLayers = graph.layers.length;
    if (stats.totalLayers === 0 && !isDomainGraph) {
      issues.push('Graph has no layers - at least 1 layer required for structural graphs');
    }

    graph.layers.forEach((layer, lIdx) => {
      if (!layer.nodeIds || !Array.isArray(layer.nodeIds)) {
        issues.push(`Layer at index ${lIdx} missing or invalid nodeIds array`);
      } else {
        layer.nodeIds.forEach(nid => {
          if (!nodeIds.has(nid)) {
            issues.push(`Layer at index ${lIdx} references non-existent node '${nid}'`);
          }
        });
      }
    });
  }

  // Check tour
  if (!graph.tour || !Array.isArray(graph.tour)) {
    if (!isDomainGraph) {
      issues.push('Missing or invalid tour array');
    }
  } else {
    stats.tourSteps = graph.tour.length;
    if (stats.tourSteps === 0 && !isDomainGraph) {
      issues.push('Graph has no tour steps - at least 1 step required for structural graphs');
    }

    // Check tour step order
    const orders = new Set();
    graph.tour.forEach((step, sIdx) => {
      if (step.order !== undefined) {
        if (orders.has(step.order)) {
          warnings.push(`Tour step at index ${sIdx} has duplicate order ${step.order}`);
        }
        orders.add(step.order);
      }
      if (!step.nodeIds || !Array.isArray(step.nodeIds) || step.nodeIds.length === 0) {
        warnings.push(`Tour step at index ${sIdx} has no nodeIds or empty nodeIds`);
      } else {
        step.nodeIds.forEach(nid => {
          if (!nodeIds.has(nid)) {
            issues.push(`Tour step at index ${sIdx} references non-existent node '${nid}'`);
          }
        });
      }
    });

    if (stats.tourSteps > 0 && stats.tourSteps < 5) {
      warnings.push(`Tour has only ${stats.tourSteps} steps - recommended range is 5-15`);
    }
    if (stats.tourSteps > 15) {
      warnings.push(`Tour has ${stats.tourSteps} steps - recommended range is 5-15`);
    }
  }

  // Check 7: Quality - orphan nodes
  const connectedNodes = new Set();
  graph.edges && graph.edges.forEach(e => {
    if (e.source) connectedNodes.add(e.source);
    if (e.target) connectedNodes.add(e.target);
  });

  const orphanNodes = [];
  graph.nodes && graph.nodes.forEach(n => {
    if (!connectedNodes.has(n.id)) {
      orphanNodes.push(n.id);
    }
  });
  if (orphanNodes.length > 0) {
    warnings.push(`${orphanNodes.length} node(s) have no edges connecting to them: ${orphanNodes.slice(0, 5).join(', ')}${orphanNodes.length > 5 ? '...' : ''}`);
  }

  // Check 7: Summary quality
  graph.nodes && graph.nodes.forEach(n => {
    if (n.summary && n.name) {
      const summaryLower = n.summary.toLowerCase();
      const nameLower = n.name.toLowerCase();
      // Check if summary just restates the name
      if (summaryLower === nameLower || summaryLower.trim() === '') {
        warnings.push(`Node '${n.id}' has a generic summary that just restates the name`);
      }
    }
  });

  // Check 8: Non-code node quality
  const documentNodes = graph.nodes && graph.nodes.filter(n => n.type === 'document');
  const serviceNodes = graph.nodes && graph.nodes.filter(n => n.type === 'service');
  const pipelineNodes = graph.nodes && graph.nodes.filter(n => n.type === 'pipeline');
  const domainNodes = graph.nodes && graph.nodes.filter(n => n.type === 'domain');
  const flowNodes = graph.nodes && graph.nodes.filter(n => n.type === 'flow');

  // For domain/flow nodes, check they have cross_domain or contains_flow edges
  if (domainNodes && domainNodes.length > 0) {
    domainNodes.forEach(d => {
      const hasContainsFlow = graph.edges && graph.edges.some(e =>
        e.source === d.id && e.type === 'contains_flow'
      );
      if (!hasContainsFlow) {
        warnings.push(`Domain node '${d.id}' has no 'contains_flow' edges`);
      }
    });
  }

  if (flowNodes && flowNodes.length > 0) {
    flowNodes.forEach(f => {
      const hasFlowStep = graph.edges && graph.edges.some(e =>
        e.source === f.id && e.type === 'flow_step'
      );
      if (!hasFlowStep) {
        warnings.push(`Flow node '${f.id}' has no 'flow_step' edges`);
      }
    });
  }

  const result = {
    scriptCompleted: true,
    issues,
    warnings,
    stats
  };

  try {
    fs.writeFileSync(outputPath, JSON.stringify(result, null, 2));
  } catch (err) {
    console.error(`Error writing results: ${err.message}`, stderr);
    process.exit(1);
  }

  process.exit(0);
}

main();

{
  "approved": true,
  "issues": [],
  "warnings": [
    "Node tags should be lowercase hyphenated (currently use single words without hyphens)",
    "Node 'domain:symbol-resolution' has no edges connecting to it",
    "Domain node 'domain:java-heap-analysis' has no 'contains_flow' edges",
    "Domain node 'domain:symbol-resolution' has no 'contains_flow' edges"
  ],
  "stats": {
    "totalNodes": 48,
    "totalEdges": 46,
    "totalLayers": 0,
    "tourSteps": 0,
    "nodeTypes": {
      "domain": 9,
      "flow": 9,
      "step": 30
    },
    "edgeTypes": {
      "contains_flow": 9,
      "flow_step": 30,
      "cross_domain": 7
    }
  }
}
